function createBaseRespEnvelope(): RespEnvelope {
  return { id: 0, error: false, errorMessage: "", payload: undefined };
}

export const RespEnvelope: MessageFns<RespEnvelope> = {
  encode(message: RespEnvelope, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.id !== 0) {
      writer.uint32(8).int32(message.id);
    }
    if (message.error !== false) {
      writer.uint32(16).bool(message.error);
    }
    if (message.errorMessage !== "") {
      writer.uint32(26).string(message.errorMessage);
    }
    switch (message.payload?.$case) {
      case "respStatus":
        Status.encode(message.payload.respStatus, writer.uint32(82).fork()).join();
        break;
      case "respAck":
        Ack.encode(message.payload.respAck, writer.uint32(90).fork()).join();
        break;
      case "respFile":
        File.encode(message.payload.respFile, writer.uint32(98).fork()).join();
        break;
      case "respListOfFiles":
        ListOfFiles.encode(message.payload.respListOfFiles, writer.uint32(106).fork()).join();
        break;
      case "respTagsList":
        TagsList.encode(message.payload.respTagsList, writer.uint32(114).fork()).join();
        break;
      case "respSettings":
        Settings.encode(message.payload.respSettings, writer.uint32(122).fork()).join();
        break;
      case "respBridgeAckOnboard":
        BridgeAckOnboard.encode(message.payload.respBridgeAckOnboard, writer.uint32(130).fork()).join();
        break;
      case "respProfile":
        Profile.encode(message.payload.respProfile, writer.uint32(138).fork()).join();
        break;
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): RespEnvelope {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseRespEnvelope();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 8) {
            break;
          }

          message.id = reader.int32();
          continue;
        }
        case 2: {
          if (tag !== 16) {
            break;
          }

          message.error = reader.bool();
          continue;
        }
        case 3: {
          if (tag !== 26) {
            break;
          }

          message.errorMessage = reader.string();
          continue;
        }
        case 10: {
          if (tag !== 82) {
            break;
          }

          message.payload = { $case: "respStatus", respStatus: Status.decode(reader, reader.uint32()) };
          continue;
        }
        case 11: {
          if (tag !== 90) {
            break;
          }

          message.payload = { $case: "respAck", respAck: Ack.decode(reader, reader.uint32()) };
          continue;
        }
        case 12: {
          if (tag !== 98) {
            break;
          }

          message.payload = { $case: "respFile", respFile: File.decode(reader, reader.uint32()) };
          continue;
        }
        case 13: {
          if (tag !== 106) {
            break;
          }

          message.payload = { $case: "respListOfFiles", respListOfFiles: ListOfFiles.decode(reader, reader.uint32()) };
          continue;
        }
        case 14: {
          if (tag !== 114) {
            break;
          }

          message.payload = { $case: "respTagsList", respTagsList: TagsList.decode(reader, reader.uint32()) };
          continue;
        }
        case 15: {
          if (tag !== 122) {
            break;
          }

          message.payload = { $case: "respSettings", respSettings: Settings.decode(reader, reader.uint32()) };
          continue;
        }
        case 16: {
          if (tag !== 130) {
            break;
          }

          message.payload = {
            $case: "respBridgeAckOnboard",
            respBridgeAckOnboard: BridgeAckOnboard.decode(reader, reader.uint32()),
          };
          continue;
        }
        case 17: {
          if (tag !== 138) {
            break;
          }

          message.payload = { $case: "respProfile", respProfile: Profile.decode(reader, reader.uint32()) };
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): RespEnvelope {
    return {
      id: isSet(object.id) ? globalThis.Number(object.id) : 0,
      error: isSet(object.error) ? globalThis.Boolean(object.error) : false,
      errorMessage: isSet(object.errorMessage) ? globalThis.String(object.errorMessage) : "",
      payload: isSet(object.respStatus)
        ? { $case: "respStatus", respStatus: Status.fromJSON(object.respStatus) }
        : isSet(object.respAck)
        ? { $case: "respAck", respAck: Ack.fromJSON(object.respAck) }
        : isSet(object.respFile)
        ? { $case: "respFile", respFile: File.fromJSON(object.respFile) }
        : isSet(object.respListOfFiles)
        ? { $case: "respListOfFiles", respListOfFiles: ListOfFiles.fromJSON(object.respListOfFiles) }
        : isSet(object.respTagsList)
        ? { $case: "respTagsList", respTagsList: TagsList.fromJSON(object.respTagsList) }
        : isSet(object.respSettings)
        ? { $case: "respSettings", respSettings: Settings.fromJSON(object.respSettings) }
        : isSet(object.respBridgeAckOnboard)
        ? {
          $case: "respBridgeAckOnboard",
          respBridgeAckOnboard: BridgeAckOnboard.fromJSON(object.respBridgeAckOnboard),
        }
        : isSet(object.respProfile)
        ? { $case: "respProfile", respProfile: Profile.fromJSON(object.respProfile) }
        : undefined,
    };
  },

  toJSON(message: RespEnvelope): unknown {
    const obj: any = {};
    if (message.id !== 0) {
      obj.id = Math.round(message.id);
    }
    if (message.error !== false) {
      obj.error = message.error;
    }
    if (message.errorMessage !== "") {
      obj.errorMessage = message.errorMessage;
    }
    if (message.payload?.$case === "respStatus") {
      obj.respStatus = Status.toJSON(message.payload.respStatus);
    } else if (message.payload?.$case === "respAck") {
      obj.respAck = Ack.toJSON(message.payload.respAck);
    } else if (message.payload?.$case === "respFile") {
      obj.respFile = File.toJSON(message.payload.respFile);
    } else if (message.payload?.$case === "respListOfFiles") {
      obj.respListOfFiles = ListOfFiles.toJSON(message.payload.respListOfFiles);
    } else if (message.payload?.$case === "respTagsList") {
      obj.respTagsList = TagsList.toJSON(message.payload.respTagsList);
    } else if (message.payload?.$case === "respSettings") {
      obj.respSettings = Settings.toJSON(message.payload.respSettings);
    } else if (message.payload?.$case === "respBridgeAckOnboard") {
      obj.respBridgeAckOnboard = BridgeAckOnboard.toJSON(message.payload.respBridgeAckOnboard);
    } else if (message.payload?.$case === "respProfile") {
      obj.respProfile = Profile.toJSON(message.payload.respProfile);
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<RespEnvelope>, I>>(base?: I): RespEnvelope {
    return RespEnvelope.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<RespEnvelope>, I>>(object: I): RespEnvelope {
    const message = createBaseRespEnvelope();
    message.id = object.id ?? 0;
    message.error = object.error ?? false;
    message.errorMessage = object.errorMessage ?? "";
    switch (object.payload?.$case) {
      case "respStatus": {
        if (object.payload?.respStatus !== undefined && object.payload?.respStatus !== null) {
          message.payload = { $case: "respStatus", respStatus: Status.fromPartial(object.payload.respStatus) };
        }
        break;
      }
      case "respAck": {
        if (object.payload?.respAck !== undefined && object.payload?.respAck !== null) {
          message.payload = { $case: "respAck", respAck: Ack.fromPartial(object.payload.respAck) };
        }
        break;
      }
      case "respFile": {
        if (object.payload?.respFile !== undefined && object.payload?.respFile !== null) {
          message.payload = { $case: "respFile", respFile: File.fromPartial(object.payload.respFile) };
        }
        break;
      }
      case "respListOfFiles": {
        if (object.payload?.respListOfFiles !== undefined && object.payload?.respListOfFiles !== null) {
          message.payload = {
            $case: "respListOfFiles",
            respListOfFiles: ListOfFiles.fromPartial(object.payload.respListOfFiles),
          };
        }
        break;
      }
      case "respTagsList": {
        if (object.payload?.respTagsList !== undefined && object.payload?.respTagsList !== null) {
          message.payload = { $case: "respTagsList", respTagsList: TagsList.fromPartial(object.payload.respTagsList) };
        }
        break;
      }
      case "respSettings": {
        if (object.payload?.respSettings !== undefined && object.payload?.respSettings !== null) {
          message.payload = { $case: "respSettings", respSettings: Settings.fromPartial(object.payload.respSettings) };
        }
        break;
      }
      case "respBridgeAckOnboard": {
        if (object.payload?.respBridgeAckOnboard !== undefined && object.payload?.respBridgeAckOnboard !== null) {
          message.payload = {
            $case: "respBridgeAckOnboard",
            respBridgeAckOnboard: BridgeAckOnboard.fromPartial(object.payload.respBridgeAckOnboard),
          };
        }
        break;
      }
      case "respProfile": {
        if (object.payload?.respProfile !== undefined && object.payload?.respProfile !== null) {
          message.payload = { $case: "respProfile", respProfile: Profile.fromPartial(object.payload.respProfile) };
        }
        break;
      }
    }
    return message;
  },
};

function bytesFromBase64(b64: string): Uint8Array {
  if ((globalThis as any).Buffer) {
    return Uint8Array.from(globalThis.Buffer.from(b64, "base64"));
  } else {
    const bin = globalThis.atob(b64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; ++i) {
      arr[i] = bin.charCodeAt(i);
    }
    return arr;
  }
}

function base64FromBytes(arr: Uint8Array): string {
  if ((globalThis as any).Buffer) {
    return globalThis.Buffer.from(arr).toString("base64");
  } else {
    const bin: string[] = [];
    arr.forEach((byte) => {
      bin.push(globalThis.String.fromCharCode(byte));
    });
    return globalThis.btoa(bin.join(""));
  }
}

type Builtin = Date | Function | Uint8Array | string | number | boolean | bigint | undefined;

export type DeepPartial<T> = T extends Builtin ? T
  : T extends globalThis.Array<infer U> ? globalThis.Array<DeepPartial<U>>
  : T extends ReadonlyArray<infer U> ? ReadonlyArray<DeepPartial<U>>
  : T extends { $case: string } ? { [K in keyof Omit<T, "$case">]?: DeepPartial<T[K]> } & { $case: T["$case"] }
  : T extends {} ? { [K in keyof T]?: DeepPartial<T[K]> }
  : Partial<T>;

type KeysOfUnion<T> = T extends T ? keyof T : never;
export type Exact<P, I extends P> = P extends Builtin ? P
  : P & { [K in keyof P]: Exact<P[K], I[K]> } & { [K in Exclude<keyof I, KeysOfUnion<P>>]: never };

function toTimestamp(date: Date): Timestamp {
  const seconds = BigInt(Math.trunc(date.getTime() / 1_000));
  const nanos = (date.getTime() % 1_000) * 1_000_000;
  return { seconds, nanos };
}

function fromTimestamp(t: Timestamp): Date {
  let millis = (globalThis.Number(t.seconds.toString()) || 0) * 1_000;
  millis += (t.nanos || 0) / 1_000_000;
  return new globalThis.Date(millis);
}

function fromJsonTimestamp(o: any): Date {
  if (o instanceof globalThis.Date) {
    return o;
  } else if (typeof o === "string") {
    return new globalThis.Date(o);
  } else {
    return fromTimestamp(Timestamp.fromJSON(o));
  }
}

function isSet(value: any): boolean {
  return value !== null && value !== undefined;
}

export interface MessageFns<T> {
  encode(message: T, writer?: BinaryWriter): BinaryWriter;
  decode(input: BinaryReader | Uint8Array, length?: number): T;
  fromJSON(object: any): T;
  toJSON(message: T): unknown;
  create<I extends Exact<DeepPartial<T>, I>>(base?: I): T;
  fromPartial<I extends Exact<DeepPartial<T>, I>>(object: I): T;
}
